3_real_world_example.code:
class Product {
  // Runs automatically when 'new Product(...)' is called
  constructor(name, price) {
    this.name = name;
    this.price = price;
    this.inStock = true; // Default value
  }
}

// Passes 'Laptop' and 1000 directly into the constructor()
const p1 = new Product('Laptop', 1000);
console.log(p1.name); // 'Laptop'

